SELECT * FROM activity
WHERE status = 'ACTIVE'
AND start_time <= #{now}
AND end_time >= #{now}
ORDER BY create_time DESC

SELECT a.id, a.name, a.description, a.rules, a.start_time AS startTime, a.end_time AS endTime, a.merchant_id AS merchantId, a.status, m.shop_name AS merchantName FROM activity a LEFT JOIN merchant m ON a.merchant_id = m.id WHERE a.status = 'ACTIVE' AND a.start_time <= #{currentTime} AND a.end_time >= #{currentTime}
AND (a.merchant_id IS NULL OR a.merchant_id = #{merchantId})
ORDER BY a.create_time DESC
